import{_ as t,o as n,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"79A. Victorian Maternal And Child Health Nurse Student","description":"","frontmatter":{"title":"79A. Victorian Maternal And Child Health Nurse Student","eba":"Nurses and Midwives 2024-2028","topics":["employment","termination","preliminary","definitions"]},"headers":[],"relativePath":"ebas/nurses-midwives/education-pd/79A-victorian-maternal-and-child-health-nurse-student.md","filePath":"ebas/nurses-midwives/education-pd/79A-victorian-maternal-and-child-health-nurse-student.md"}'),r={name:"ebas/nurses-midwives/education-pd/79A-victorian-maternal-and-child-health-nurse-student.md"};function i(s,e,l,d,p,h){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_79a-victorian-maternal-and-child-health-nurse-student" tabindex="-1">79A. Victorian Maternal And Child Health Nurse Student <a class="header-anchor" href="#_79a-victorian-maternal-and-child-health-nurse-student" aria-label="Permalink to &quot;79A. Victorian Maternal And Child Health Nurse Student&quot;">​</a></h1><p><strong>79A.1</strong> Definition</p><p>Victorian Maternal and Child Health Nurse Student or VMCHNS for the purposes of this clause is a Registered Nurse and Midwife enrolled in an accredited post graduate degree/diploma (or equivalent) in child and family health.</p><p><strong>79A.2</strong> Employment VMCHNS</p><p><strong>(a)</strong> VMCHNS will be employed on a fixed term basis or engaged on a casual basis.</p><p><strong>(b)</strong> An Employer operating a maternal and child health service may enter into an agreement with the ANMF to facilitate employment of VMCHNS in accordance with these provisions.</p><p><strong>79A.3</strong> Termination of Employment</p><p><strong>(a)</strong> Employment will conclude:</p><p><strong>(i)</strong> from when the Employee terminates their employment;</p><p><strong>(ii)</strong> from when the Employer terminates the employment in accordance with this Agreement;</p><p><strong>(iii)</strong> when the Employee withdraws, defers from or fails their course of education;</p><p><strong>(iv)</strong> on completion of the education necessary to work as a Maternal and Child Health Nurse; or</p><p><strong>(v)</strong> in the case of a casual, in accordance with <a href="/eba/ebas/doctors-in-training/doctor-employment/19-casual-employment.html">clause 19</a> (Casual Employment).</p><p><strong>79A.4</strong> Rate of pay for VMCHNS</p><p>A VMCHNS will be paid 95% of the rate for a Maternal and Child Health Nurse set out in Part 1 of <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>.</p><p><strong>79A.5</strong> Other terms and conditions for VMCHNS</p><p>All other terms and conditions of employment will be those applying to a Registered Nurse/Registered Midwife under this Agreement except where this clause explicitly says otherwise.</p><p><strong>79A.6</strong> Continuity of service</p><p>Continuity of Service as a Registered Nurse/Registered Midwife will include any period of service in the program, provided any gap between employment as a student and commencement of employment as a Registered Nurse/Registered Midwife is less than 12 months.</p><p><strong>79A.7</strong> Notification to ANMF regarding commencement of a VMCHNS model</p><p>The Employer will, prior to commencing a model, provide to the ANMF:</p><p><strong>(a)</strong> the proposed Position Description;</p><p><strong>(b)</strong> the proposed Core activity list;</p><p><strong>(c)</strong> the proposed Exclusion List; and</p><p><strong>(d)</strong> the proposed supervision arrangements.</p><p>The Employer will consult with the ANMF about the matters at (a) to (d) above.</p><p>Plain language terms: MCHN student, child health nurse student.</p>',27)])])}const u=t(r,[["render",i]]);export{m as __pageData,u as default};
